{"code": "import json
import re

# Get female BRCA patient data
clinical_data = var_functions.query_db:10
if isinstance(clinical_data, str):
    with open(clinical_data, 'r') as f:
        clinical_data = json.load(f)

# Get CDH1 mutation data
mutation_data = var_functions.query_db:12
if isinstance(mutation_data, str):
    with open(mutation_data, 'r') as f:
        mutation_data = json.load(f)

# Extract patient barcodes and histological types
patients = []
for record in clinical_data:
    patient_desc = record.get('Patient_description', '')
    hist_type = record.get('histological_type', '')

    # Extract barcode using regex
    match = re.search(r'(TCGA-\w{2}-\w{4})', patient_desc)
    if match:
        barcode = match.group(1)
        patients.append({'barcode': barcode, 'hist_type': hist_type})

# Get CDH1 mutation patients
cdh1_patients = set(m.get('ParticipantBarcode') for m in mutation_data if m.get('Hugo_Symbol') == 'CDH1' and m.get('FILTER') == 'PASS')

# Add mutation status
for p in patients:
    p['has_cdh1'] = p['barcode'] in cdh1_patients

# Group by histological type
grouped = {}
for p in patients:
    hist = p['hist_type']
    if hist not in grouped:
        grouped[hist] = {'with_cdh1': 0, 'without_cdh1': 0}
    if p['has_cdh1']:
        grouped[hist]['with_cdh1'] += 1
    else:
        grouped[hist]['without_cdh1'] += 1

result = {
    'total_patients': len(patients),
    'patients_with_cdh1': len(cdh1_patients),
    'grouped_data': grouped
}

print('__RESULT__:')
print(json.dumps(result))"}
